INSERT INTO public.articles VALUES ('c1000001-0001-4000-8000-000000000001', NULL, 'a1b2c3d4-0001-4000-8000-000000000001', 'Tesla begins Optimus production at Fremont factory, targets 1M units/year capacity', 'Electrek', 'https://electrek.co/2026/04/22/tesla-optimus-production-fremont-model-sx-line/', '2026-04-22 00:00:00', 'Tesla will begin Optimus robot production at Fremont in late July/August 2026, converting the former Model S/X line. Initial output will be slow given 10,000 unique parts. A second-generation facility at Giga Texas targets 10M units/year long-term.', NULL, 'en', '9c0410f357207efcf106af45c79dc402', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000001-0002-4000-8000-000000000002', NULL, 'a1b2c3d4-0001-4000-8000-000000000001', 'Tesla Optimus Gen 3 hands revealed: 22 DOF, 50 actuators with tactile fingertip sensors', 'Basenor', 'https://www.basenor.com/blogs/news/tesla-optimus-gen-3-hands-22-dof-50-actuators-explained', '2026-03-15 00:00:00', 'Gen 3 hands feature 22 degrees of freedom per hand, powered by 50 actuators total (25 per forearm/hand) - a 4.5x increase from Gen 2. Includes biomimetic tendon-driven design and tactile fingertip sensors for delicate object manipulation. Total robot DOF now 72+.', NULL, 'en', '20be676dcc4d6190458eaee69ec193a0', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'technology', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000001-0003-4000-8000-000000000003', NULL, 'a1b2c3d4-0001-4000-8000-000000000001', 'Tesla targets 10M Optimus units with new Texas plant, external sales to begin in 2026', 'The Robot Report', 'https://www.therobotreport.com/from-evs-to-robotics-tesla-targets-10m-optimus-units-with-new-texas-plant/', '2026-05-10 00:00:00', 'Tesla is breaking ground on a second-generation Optimus manufacturing facility at Giga Texas. Musk positions Optimus as highest-volume product ever, with initial external sales to begin in 2026.', NULL, 'en', 'c13c13897b6ff34dea7f24fd2682b946', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000002-0001-4000-8000-000000000001', NULL, '745abfe6-5438-4eda-b916-edf2e482c017', 'Boston Dynamics unveils production-ready Atlas at CES 2026, all 2026 deployments committed', 'Engadget', 'https://www.engadget.com/big-tech/boston-dynamics-unveils-production-ready-version-of-atlas-robot-at-ces-2026-234047882.html', '2026-01-05 00:00:00', 'Boston Dynamics unveiled production version of electric Atlas at CES 2026. Specs: 7.5ft reach, 110lb lift capacity, -4 to 104°F operating range. All 2026 deployments fully committed to Hyundai RMAC and Google DeepMind.', NULL, 'en', '5725f5fa90803fcceae2be0bb0c5a7a9', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'product', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000002-0002-4000-8000-000000000002', NULL, '745abfe6-5438-4eda-b916-edf2e482c017', 'Boston Dynamics partners with Google DeepMind for Atlas foundation models', 'Boston Dynamics Blog', 'https://bostondynamics.com/blog/boston-dynamics-unveils-new-atlas-robot-to-revolutionize-industry/', '2026-01-05 00:00:00', 'Partnership with Google DeepMind to integrate cutting-edge foundation models into Atlas for enhanced cognitive capabilities. Atlas demonstrated whole-body control lifting 100lb fridge through RL training with millions of hours of simulation.', NULL, 'en', '74af21dcb57bd302d2539cfafa60c3be', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'technology', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000002-0003-4000-8000-000000000003', NULL, '745abfe6-5438-4eda-b916-edf2e482c017', 'Atlas robot demonstrates 100lb heavy lifting through AI-driven whole-body control', 'Robotics and Automation News', 'https://roboticsandautomationnews.com/2026/05/20/boston-dynamics-trains-atlas-humanoid-robot-to-pick-up-and-place-washing-machine/101759/', '2026-05-20 00:00:00', 'Atlas trained via reinforcement learning to lift and carry 100+ pound objects (washing machine, fridge). Practiced millions of simulated hours on GPUs with varying weight, friction, grip, and positioning conditions.', NULL, 'en', 'df5f3c456f172da3948022f38fe5c3b1', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'technology', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000003-0001-4000-8000-000000000001', NULL, 'a1b2c3d4-0002-4000-8000-000000000002', 'Figure AI ramps Figure 03 production to 1 robot per hour, 24x throughput improvement', 'The AI Insider', 'https://theaiinsider.tech/2026/05/01/figure-ai-ramps-up-production-to-one-humanoid-robot-per-hour/', '2026-05-01 00:00:00', 'Figure AI increased Figure 03 production from 1 unit/day to 1/hour in under 120 days - a 24x throughput improvement. Over 350 units delivered. BotQ manufacturing facility capable of 12,000 units/year.', NULL, 'en', 'a7a137591413bde5122dc3be9feb8ff2', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000003-0002-4000-8000-000000000002', NULL, 'a1b2c3d4-0002-4000-8000-000000000002', 'Figure 02 contributed to production of 30,000 cars at BMW', 'Figure AI', 'https://www.figure.ai/news/production-at-bmw', '2026-04-15 00:00:00', 'Figure 02 robots contributed to the production of 30,000 cars at BMW Spartanburg plant, demonstrating sustained commercial deployment capability in automotive manufacturing.', NULL, 'en', 'ed6689d8470d829098f45a63b130c07b', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000003-0003-4000-8000-000000000003', NULL, 'a1b2c3d4-0002-4000-8000-000000000002', 'Figure AI raises $1B+ Series C at $39B valuation, led by Parkway with Nvidia, Intel Capital', 'Forge Global', 'https://forgeglobal.com/insights/figure-ai-robotics-growth-2026/', '2025-12-15 00:00:00', 'Figure AI raised over $1 billion in Series C funding at approximately $39 billion valuation (15x YoY increase). Investors include Nvidia, Intel Capital, Qualcomm Ventures, and Salesforce.', NULL, 'en', 'b350a9f801a2063dcf68c0b4a45e052f', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000004-0001-4000-8000-000000000001', NULL, '5f15c903-5393-42bb-bc31-1b00deacb922', 'Nvidia selects Unitree H2 for first robotics reference platform with Jetson Thor', 'CNBC', 'https://www.cnbc.com/2026/06/01/nvidia-unitree-humanoid-robotics-system-researchers.html', '2026-06-01 00:00:00', 'Nvidia selected Unitree H2 as its first commercial robotics system for researchers, combining the humanoid with Jetson Thor computing. Part of NVIDIA Isaac GR00T reference design initiative.', NULL, 'en', 'f8419a587a87b344a6fab4dcd599dccb', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'technology', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000004-0002-4000-8000-000000000002', NULL, '5f15c903-5393-42bb-bc31-1b00deacb922', 'Unitree targets 20,000 humanoid robot shipments in 2026, IPO mid-2026 at $580M', 'eWeek', 'https://www.eweek.com/news/unitree-20000-humanoid-robots-2026-china/', '2026-03-15 00:00:00', 'Unitree plans to ship 20,000 humanoid robots in 2026 (up from 5,500 in 2025). A-share IPO on track for mid-2026 at $580M target. Revenue grew 335% YoY in 2025 to ¥1.708B.', NULL, 'en', '46a315c017763974f5ec4c85b62d2e67', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000004-0003-4000-8000-000000000003', NULL, '5f15c903-5393-42bb-bc31-1b00deacb922', 'Unitree G1 deployed at Tokyo Haneda Airport with Japan Airlines - first commercial airport humanoid', 'Unitree / Japan Airlines', 'https://blog.robozaps.com/b/unitree-g1-review', '2026-02-01 00:00:00', 'Unitree G1 deployed for baggage/cargo handling at Tokyo Haneda Airport in partnership with Japan Airlines and GMO Internet Group. First commercial airport deployment for a humanoid robot, trials through 2028.', NULL, 'en', 'e9ccc366048582d3b07cadfd39795118', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000005-0001-4000-8000-000000000001', NULL, 'e00953cf-d9b2-4c6c-bc5e-c0700a7f3a89', 'Agility Robotics signs commercial RaaS agreement with Toyota Canada for Digit deployment', 'Robotics and Automation News', 'https://roboticsandautomationnews.com/2026/02/20/toyota-canada-to-deploy-agility-robotics-humanoid-digit-in-manufacturing-operations/99011/', '2026-02-20 00:00:00', 'Agility signed Robots-as-a-Service agreement with Toyota Motor Manufacturing Canada (Woodstock) for RAV4 logistics support. Starting with 3 units with expansion planned. 7+ commercial units now active.', NULL, 'en', '296bb64951e62191ab07f9906fdd2976', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000005-0002-4000-8000-000000000002', NULL, 'e00953cf-d9b2-4c6c-bc5e-c0700a7f3a89', 'Digit surpasses 100,000 totes milestone at GXO facility, pursuing ISO functional safety certification', 'Agility Robotics', 'https://www.agilityrobotics.com/content/digit-moves-over-100k-totes', '2026-04-10 00:00:00', 'Digit moved over 100,000 totes at GXO Flowery Branch facility. ISO functional safety certification targeted for mid-to-late 2026 - would make Digit first humanoid cleared to work alongside humans without barriers.', NULL, 'en', 'e620faf799659dbca93ec2f734c1840e', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000006-0001-4000-8000-000000000001', NULL, 'a1b2c3d4-0003-4000-8000-000000000003', 'Apptronik raises $520M at $5B valuation for Apollo robot, total Series A reaches $935M', 'CNBC', 'https://www.cnbc.com/2026/02/11/apptronik-raises-520-million-at-5-billion-valuation-for-apollo-robot.html', '2026-02-11 00:00:00', 'Apptronik raised $520M at $5B valuation, co-led by B Capital and Google. Total Series A funding now $935M. Partnerships with Mercedes-Benz, GXO Logistics, Jabil. Working with Google DeepMind on Gemini Robotics models for Apollo.', NULL, 'en', '1945aac1e96b2fc67065853c645cc9e1', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000006-0002-4000-8000-000000000002', NULL, 'a1b2c3d4-0003-4000-8000-000000000003', 'Apptronik hires key executives from Waymo, Boston Dynamics, Amazon for Apollo commercialization', 'Yahoo Finance', 'https://finance.yahoo.com/sectors/technology/articles/apptronik-accelerates-commercialization-humanoid-robots-130000528.html', '2026-04-15 00:00:00', 'Strategic executive hires: Daniel Chu as CPO, alongside senior leaders from Waymo, Boston Dynamics, and Amazon. Plans to expand Austin operations, open California office, scale Apollo production. Expects $1B in orders starting 2027.', NULL, 'en', '16421b299d7d3ed72b4273cce728bba2', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000007-0001-4000-8000-000000000001', NULL, 'a1b2c3d4-0004-4000-8000-000000000004', '1X Technologies opens California factory, first-year production sold out in 5 days', 'Tech Funding News', 'https://techfundingnews.com/openai-backed-1x-first-us-humanoid-factory-sold-out-production/', '2026-01-15 00:00:00', '1X opened 58,000 sq ft factory in Hayward, CA with 10,000 NEO unit/year capacity. Entire first-year production sold out within 5 days. Consumer shipments planned before end of 2026, targeting 100,000 units by end of 2027.', NULL, 'en', '62078b18cf08da56a5385a78973bb316', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000007-0002-4000-8000-000000000002', NULL, 'a1b2c3d4-0004-4000-8000-000000000004', '1X strikes deal to deploy 10,000 NEO robots to EQT portfolio companies through 2030', 'TechCrunch', 'https://techcrunch.com/2025/12/11/1x-struck-a-deal-to-send-its-home-humanoids-to-factories-and-warehouses/', '2025-12-11 00:00:00', 'Deal to ship up to 10,000 NEO robots to EQT''s 300+ portfolio companies (2026-2030), focusing on manufacturing, warehousing, logistics. NEO priced at $20,000 or $499/month rental (6-month min).', NULL, 'en', '6ae60b018be3474b5922efee0231d586', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000007-0003-4000-8000-000000000003', NULL, 'a1b2c3d4-0004-4000-8000-000000000004', '1X launches world model enabling NEO to learn tasks by watching videos', 'The Robot Report', 'https://www.therobotreport.com/1x-launches-world-model-enabling-neo-robot-to-learn-tasks-by-watching-videos/', '2026-03-01 00:00:00', 'AI update enables NEO to turn any request into an AI capability on demand using a video model grounded in real-world physics. Can perform tasks with objects and environments never encountered before.', NULL, 'en', '6bf03d4f63727a46cdf5ac3a9503f7fa', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'technology', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000008-0001-4000-8000-000000000001', NULL, 'a1b2c3d4-0005-4000-8000-000000000005', 'Agibot rolls out 10,000th humanoid robot, 5K to 10K in just 3 months', 'The Robot Report', 'https://www.therobotreport.com/agibot-rolls-out-10000th-humanoid-robot/', '2026-03-20 00:00:00', 'AGIBOT produced its 10,000th humanoid robot off Shanghai assembly line. Acceleration: ~2 years for first 1,000; 1 year from 1K-5K; only 3 months from 5K-10K. Ranked #1 globally in humanoid shipment volume.', NULL, 'en', '8ebc028b0de1967b3daedddcad36a4e2', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000008-0002-4000-8000-000000000002', NULL, 'a1b2c3d4-0005-4000-8000-000000000005', 'LG Electronics CEO visits Agibot in Shanghai, explores mass production and data training collaboration', 'The Korea Herald', 'https://www.koreaherald.com/article/10694574', '2026-03-15 00:00:00', 'LG Electronics CEO Lyu Jae-cheol visited Agibot during 3-day Shanghai trip. Toured facilities, discussed mass production systems, data training infrastructure, and actuator supply chains. LG took equity stake in Agibot in Aug 2025.', NULL, 'en', '2f48b37ff3cb5b5dd4a0bc394ddd814f', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
INSERT INTO public.articles VALUES ('c1000008-0003-4000-8000-000000000003', NULL, 'a1b2c3d4-0005-4000-8000-000000000005', 'Unitree-Agibot duopoly captures ~80% of China humanoid market, 94% output surge forecast for 2026', 'TrendForce', 'https://www.trendforce.com/presscenter/news/20260409-13007.html', '2026-04-09 00:00:00', 'TrendForce forecasts 94% surge in Chinese humanoid robot output for 2026. Unitree and Agibot combined projected to capture ~80% of Chinese shipments. Agibot entered US market at CES 2026 with A2, X2, G2, and D1 series.', NULL, 'en', '2125117bde1bffda3f9bcb1ddeded4ee', '2026-06-05 00:15:16.236041', '2026-06-05 00:15:16.236041', 'industry', 'robot', NULL, NULL);
