INSERT INTO public.competitive_alerts VALUES ('aa000001-0001-4000-8000-000000000001', NULL, 'mass_production', 'critical', '[Tesla] Optimus Fremont 양산라인 전환 확정 - Q3 2026 생산 시작', 'Tesla가 Model S/X 라인을 Optimus 로봇 양산라인으로 전환, 2026년 7-8월 생산 시작 예정. 연간 100만대 생산 목표. Giga Texas에 2세대 시설 착공하여 장기 1,000만대 목표.', '{"date": "Q3 2026", "event": "production_start", "company": "Tesla", "product": "Optimus Gen 3", "sources": ["Electrek", "The Robot Report"], "capacity": "1M/yr", "confidence": "B"}', false, NULL, NULL, '2026-06-05 00:19:10.763198');
INSERT INTO public.competitive_alerts VALUES ('aa000001-0002-4000-8000-000000000002', NULL, 'partnership', 'critical', '[Boston Dynamics] Google DeepMind 파트너십 + Atlas 2026년 배치 전량 확정', 'CES 2026에서 생산형 Atlas 공개. Google DeepMind와 파운데이션 모델 통합 파트너십 체결. 2026년 배치 물량 전량 Hyundai RMAC 및 Google DeepMind에 확정.', '{"event": "partnership_and_deployment", "company": "Boston Dynamics", "product": "Atlas Electric", "sources": ["Boston Dynamics Official", "Engadget"], "partners": ["Google DeepMind", "Hyundai"], "confidence": "A"}', false, NULL, NULL, '2026-06-05 00:19:10.763198');
INSERT INTO public.competitive_alerts VALUES ('aa000001-0003-4000-8000-000000000003', NULL, 'funding', 'critical', '[Figure AI] Series C $1B+ 유치, 밸류에이션 $39B (15배 증가)', 'Figure AI가 $1B+ Series C 펀딩 완료. 밸류에이션 $39B로 전년 대비 15배 성장. Nvidia, Intel Capital, Qualcomm Ventures 참여. Figure 03 시간당 1대 생산, BotQ 시설 12,000대/년.', '{"event": "series_c_funding", "amount": "$1B+", "company": "Figure AI", "product": "Figure 03", "sources": ["Forge Global", "BeginnersinAI"], "valuation": "$39B", "confidence": "A"}', false, NULL, NULL, '2026-06-05 00:19:10.763198');
INSERT INTO public.competitive_alerts VALUES ('aa000001-0004-4000-8000-000000000004', NULL, 'partnership', 'warning', '[Unitree] NVIDIA Jetson Thor 레퍼런스 로봇으로 선정, IPO 추진', 'Nvidia가 Unitree H2를 첫 로봇 레퍼런스 시스템으로 선정 (Jetson Thor + GR00T). JAL 하네다 공항 배치 (최초 공항 휴머노이드). IPO $580M 목표 mid-2026.', '{"event": "nvidia_partnership_ipo", "company": "Unitree", "product": "H2", "sources": ["CNBC", "eWeek"], "partners": ["NVIDIA", "Japan Airlines"], "confidence": "B", "ipo_target": "$580M"}', false, NULL, NULL, '2026-06-05 00:19:10.763198');
INSERT INTO public.competitive_alerts VALUES ('aa000001-0005-4000-8000-000000000005', NULL, 'partnership', 'warning', '[Agility] Toyota Canada RaaS 계약 체결, ISO 안전인증 추진', 'Toyota Motor Manufacturing Canada와 RaaS 계약 (RAV4 물류). GXO에서 100,000+ tote 처리 달성. ISO 기능안전 인증 2026 중후반 목표 (업계 최초 휴머노이드).', '{"event": "toyota_raas_iso_cert", "company": "Agility Robotics", "product": "Digit", "sources": ["Agility Official", "R&A News"], "partners": ["Toyota Canada", "GXO", "Amazon"], "confidence": "A"}', false, NULL, NULL, '2026-06-05 00:19:10.763198');
INSERT INTO public.competitive_alerts VALUES ('aa000001-0006-4000-8000-000000000006', NULL, 'funding', 'warning', '[Apptronik] $520M 추가 유치, $5B 밸류에이션, Google DeepMind 협력', 'Series A 총 $935M 확보 ($520M 추가), $5B 밸류에이션. Google DeepMind과 Gemini Robotics 모델 협력. Mercedes-Benz, GXO, Jabil 파트너십. 2027년 $1B 주문 기대.', '{"event": "funding_round", "total": "$935M", "amount": "$520M", "company": "Apptronik", "product": "Apollo", "sources": ["CNBC", "SiliconAngle"], "valuation": "$5B", "confidence": "A"}', false, NULL, NULL, '2026-06-05 00:19:10.763198');
INSERT INTO public.competitive_alerts VALUES ('aa000001-0007-4000-8000-000000000007', NULL, 'mass_production', 'warning', '[1X] NEO 첫해 생산량 5일만에 완판, EQT 10,000대 대규모 계약', 'Hayward CA 공장 10,000대/년 생산 능력. 첫해 물량 5일 만에 완판. EQT 포트폴리오 300+ 기업 대상 10,000대 배치 계약(2026-2030). NEO $20,000 or $499/month 렌탈.', '{"deal": "EQT 10K robots", "event": "production_sellout", "company": "1X Technologies", "product": "NEO", "sources": ["Tech Funding News", "TechCrunch"], "capacity": "10K/yr", "confidence": "A"}', false, NULL, NULL, '2026-06-05 00:19:10.763198');
INSERT INTO public.competitive_alerts VALUES ('aa000001-0008-4000-8000-000000000008', NULL, 'mass_production', 'critical', '[Agibot] 10,000번째 로봇 생산, LG전자 CEO 방문 협력 강화', 'Agibot이 10,000번째 휴머노이드 로봇 생산(3개월 만에 5K→10K). 글로벌 출하량 1위. LG전자 CEO 상하이 방문, 양산/데이터학습/액추에이터 협력 논의. CES 2026 미국 시장 진출.', '{"event": "10k_production_lg_partnership", "company": "Agibot", "product": "A2/X1", "sources": ["The Robot Report", "Korea Herald", "TrendForce"], "lg_visit": true, "confidence": "A/B", "units_produced": 10000}', false, NULL, NULL, '2026-06-05 00:19:10.763198');
